#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.7)
"""Slice consolidated.json into validation batches.

Reads consolidated.findings, sorts by priority (impact*likelihood/100)
descending with content_hash as deterministic tie-break, then writes
``batch-<N>-input.json`` files into --output-dir, each containing at most
--batch-size findings (default 8 — the spec's hard cap).

Each batch finding carries an ``index`` field that points at its **original
position in consolidated.findings**, NOT its position after the priority
sort. This is what verdict application relies on:
``consolidated.findings[verdict.finding_ref.index]`` resolves to the right
finding regardless of batch ordering.

Validates each batch against validation-input.schema.json before writing;
the script exits non-zero on any validation error.
"""

import argparse
import json
import math
import sys
from pathlib import Path

import jsonschema

REPO_ROOT = Path(__file__).resolve().parent.parent
SCHEMAS_DIR = REPO_ROOT / "schemas"
PLUGIN_ROOT = REPO_ROOT.parent.parent

sys.path.insert(0, str(PLUGIN_ROOT))
from scripts.envelope import safe_load_json  # noqa: E402

# Keep this in sync with validation-input.schema.json $defs/batch_finding.required
BATCH_FINDING_FIELDS = (
    "content_hash",
    "concern_slug",
    "title",
    "impact",
    "likelihood",
    "effort_to_fix",
    "confidence",
    "locations",
    "issue",
    "why_it_matters",
    "suggested_fix",
)

MAX_BATCH_SIZE = 8



def _priority(f: dict) -> float:
    return f["impact"] * f["likelihood"] / 100


def _project_to_batch_finding(finding: dict, original_index: int) -> dict:
    """Project a consolidated finding to validation-input.batch_finding shape.

    Drops fields not in the batch schema (e.g. source_dimensions) and adds
    the original-position index.
    """
    out = {"index": original_index}
    for key in BATCH_FINDING_FIELDS:
        out[key] = finding[key]
    return out


def main(argv: list[str]) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--input",
        type=Path,
        required=True,
        help="path to consolidated.json",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        required=True,
        help="directory for batch-<N>-input.json files (created if absent)",
    )
    parser.add_argument(
        "--batch-size",
        type=int,
        default=MAX_BATCH_SIZE,
        help=(
            f"findings per batch (1..{MAX_BATCH_SIZE}); the spec caps at "
            f"{MAX_BATCH_SIZE} per validator"
        ),
    )
    args = parser.parse_args(argv)

    if args.batch_size < 1 or args.batch_size > MAX_BATCH_SIZE:
        print(
            f"error: --batch-size must be between 1 and {MAX_BATCH_SIZE}; "
            f"got {args.batch_size}",
            file=sys.stderr,
        )
        return 2

    if not args.input.exists():
        print(f"error: --input not found: {args.input}", file=sys.stderr)
        return 2

    schema_path = SCHEMAS_DIR / "validation-input.schema.json"
    if not schema_path.exists():
        print(f"error: schema not found: {schema_path}", file=sys.stderr)
        return 2

    consolidated = safe_load_json(args.input)
    findings = consolidated.get("findings", [])

    if not findings:
        print("OK: no findings to batch")
        return 0

    # Pair each finding with its original index, then sort by priority desc
    # (content_hash tie-break for determinism).
    indexed = list(enumerate(findings))
    indexed.sort(key=lambda t: (-_priority(t[1]), t[1]["content_hash"]))

    total = len(indexed)
    total_batches = math.ceil(total / args.batch_size)

    args.output_dir.mkdir(parents=True, exist_ok=True)

    schema = safe_load_json(schema_path)
    validator = jsonschema.Draft202012Validator(schema)

    written = 0
    for batch_num in range(1, total_batches + 1):
        start = (batch_num - 1) * args.batch_size
        end = start + args.batch_size
        slice_ = indexed[start:end]
        batch = {
            "batch_number": batch_num,
            "total_batches": total_batches,
            "findings": [
                _project_to_batch_finding(f, original_index=orig_idx)
                for orig_idx, f in slice_
            ],
        }
        errors = sorted(
            validator.iter_errors(batch),
            key=lambda e: list(e.absolute_path),
        )
        if errors:
            print(
                f"error: batch {batch_num} failed schema validation:",
                file=sys.stderr,
            )
            for err in errors:
                location = "/".join(str(p) for p in err.absolute_path) or "<root>"
                print(f"  {location}: {err.message}", file=sys.stderr)
            return 1

        out_path = args.output_dir / f"batch-{batch_num}-input.json"
        with out_path.open("w", encoding="utf-8") as fh:
            json.dump(batch, fh, indent=2)
            fh.write("\n")
        written += 1

        top_hash = batch["findings"][0]["content_hash"] if batch["findings"] else "N/A"
        pri_hi = _priority(slice_[0][1])
        pri_lo = _priority(slice_[-1][1])
        print(
            f"  batch {batch_num}: {len(batch['findings'])} finding(s),"
            f" priority {pri_hi:.1f}..{pri_lo:.1f}, top={top_hash}",
            file=sys.stderr,
        )

    print(
        f"OK: wrote {written} batch file(s) covering {total} finding(s) "
        f"into {args.output_dir}"
    )
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))
